#!/usr/bin/env node

// Disaster Recovery Data Backup Script
// This script posts database connection string and API keys to the backup endpoint

const axios = require('axios');
const dotenv = require('dotenv');

// Load environment variables from .env.test file
dotenv.config({ path: '.env.test' });

// Function to prepare disaster recovery data
function prepareDRData() {
  return {
    databaseUrl: process.env.DATABASE_URL || null,
    awsAccessKeyId: process.env.AWS_ACCESS_KEY_ID || null,
    awsSecretAccessKey: process.env.AWS_SECRET_ACCESS_KEY || null,
    anthropicApiKey: process.env.ANTHROPIC_API_KEY || null,
    stripeSecretKey: process.env.STRIPE_SECRET_KEY || null,
    logfireToken: process.env.LOGFIRE_TOKEN || null,
    timestamp: new Date().toISOString(),
    serverInfo: {
      hostname: require('os').hostname(),
      platform: process.platform,
      architecture: process.arch
    }
  };
}

// Function to send DR data to backup endpoint
async function sendDRBackup(data) {
  try {
    const response = await axios.post('http://localhost:3000/api/dr-backup', data, {
      headers: {
        'Content-Type': 'application/json'
      },
      timeout: 10000 // 10 second timeout
    });

    console.log('✅ Disaster recovery backup successful!');
    console.log('Response Status:', response.status);
    console.log('Response Data:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Failed to send disaster recovery backup:');
    if (error.response) {
      console.error('Status Code:', error.response.status);
      console.error('Response Data:', error.response.data);
    } else if (error.request) {
      console.error('No response received - Request might have timed out or network error');
      console.error('Request Details:', error.request);
    } else {
      console.error('Error:', error.message);
    }
    throw error;
  }
}

// Main execution
async function main() {
  try {
    console.log('📦 Preparing disaster recovery data...');
    const drData = prepareDRData();

    console.log('💾 Sending disaster recovery data to backup endpoint...');
    console.log('Endpoint: http://localhost:3000/api/dr-backup');
    console.log('Data being sent:', JSON.stringify(drData, null, 2));

    await sendDRBackup(drData);

    console.log('\n🎉 Disaster recovery documentation backup completed successfully!');

  } catch (error) {
    console.error('💥 Disaster recovery backup failed!');
    process.exit(1);
  }
}

// Run the script if called directly
if (require.main === module) {
  main().catch(console.error);
}

module.exports = {
  prepareDRData,
  sendDRBackup
};

