// Secure application with proper error handling and validation
const express = require('express');
const helmet = require('helmet'); // For security headers
const rateLimit = require('express-rate-limit'); // For rate limiting
const xss = require('xss-clean'); // For XSS protection
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet());
app.use(cors());

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Body parsing middleware
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// Input sanitization
app.use(xss());

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.status(200).json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with proper validation
app.get('/users', (req, res) => {
  try {
    // Basic parameter validation (if any parameters were expected)
    const { page, limit } = req.query;

    // Validate query parameters
    if (page && (isNaN(page) || page < 1)) {
      return res.status(400).json({ 
        error: 'Invalid page parameter. Must be a positive number.' 
      });
    }

    if (limit && (isNaN(limit) || limit < 1 || limit > 100)) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be between 1 and 100.' 
      });
    }

    // Mock data - in real app, this would come from database
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.status(200).json(users);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

// 404 handler
app.use('*', (req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

// Start server with error handling
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
}).on('error', (error) => {
  console.error('Server failed to start:', error);
});

module.exports = app;

